    "name": "@black-atom-industries/shiplog",
    "version": "0.3.0",
    "license": "MIT",
    "exports": "./src/main.ts",
    "tasks": {
        "install": "deno install --global -f --allow-run --allow-read --allow-env --allow-net --allow-write --name shiplog --config deno.json src/main.ts",
        "compile": "deno compile --allow-run --allow-read --allow-env --allow-net --allow-write --output shiplog src/main.ts",
        "schema": "deno run --allow-read --allow-env --allow-write scripts/generate-schema.ts",
        "test": "deno test --allow-read --allow-env --allow-write",
        "check": "deno check .",
        "lint": "deno lint",
        "fmt": "deno fmt"
    },
    "imports": {
        "@cliffy/command": "jsr:@cliffy/command@^1.0.0",
        "@cliffy/prompt": "jsr:@cliffy/prompt@^1.0.0",
        "@std/toml": "jsr:@std/toml@^1.0.11",
        "@std/fmt/colors": "jsr:@std/fmt@1.0.9/colors",
        "@tanstack/ai": "npm:@tanstack/ai@^0.6.3",
        "@tanstack/ai-anthropic": "npm:@tanstack/ai-anthropic@^0.6.0",
        "zod": "npm:zod@^4.3.6"
    },
    "fmt": {
        "useTabs": false,
        "lineWidth": 100,
        "indentWidth": 4,
        "semiColons": true,
        "singleQuote": false,
        "exclude": [
            "CHANGELOG.md"
        ]
    },
    "lint": {
        "rules": {
            "exclude": [
                "no-slow-types"
            ]
        }
    }
}

import { chat } from "@tanstack/ai";
import { createAdapter, type ModelName, type ProviderName } from "../adapters.ts";

export async function generate(
    prompt: string,
    model: ModelName,
    provider: ProviderName,
): Promise<string> {
    const adapter = createAdapter(provider, model);

    const stream = chat({
        adapter,
        messages: [{ role: "user", content: prompt }],
    });

    let text = "";
    for await (const chunk of stream) {
        if (chunk.type === "RUN_ERROR") {
            throw new Error(chunk.error.message);
        }
        if (chunk.type === "TEXT_MESSAGE_CONTENT") {
            text += chunk.delta;
        }
    }

    return text.trim();
}

import { z } from "zod";
import { ANTHROPIC_MODELS, PROVIDER_NAMES } from "../adapters.ts";

export const GlobalConfigSchema = z.object({
    provider: z.enum(PROVIDER_NAMES).default("anthropic"),
    model: z.enum(ANTHROPIC_MODELS).default("claude-haiku-4-5"),
    models: z.array(z.enum(ANTHROPIC_MODELS)).default([
        "claude-opus-4-5",
        "claude-sonnet-4-5",
        "claude-haiku-4-5",
    ]),
    summaryLength: z.number().positive().default(72),
    historyCount: z.number().positive().default(10),
});

export const DEFAULT_SCOPES = [
    "ui",
    "api",
    "config",
    "auth",
    "ci",
    "build",
    "docs",
    "test",
] as const;

export const DEFAULT_COMMIT_TYPES = [
    "feat",
    "fix",
    "docs",
    "style",
    "refactor",
    "test",
    "chore",
    "ci",
    "perf",
    "revert",
] as const;

export const RepoConfigSchema = z.object({
    issuePattern: z.string().optional(),
    issuePrefix: z.string().optional(),
    useLazygit: z.boolean().default(true),
    commitTypes: z.array(z.string()).default([...DEFAULT_COMMIT_TYPES]),
    scopes: z.array(z.string()).default([...DEFAULT_SCOPES]),
});

export const MergedConfigSchema = z.object({
    ...GlobalConfigSchema.shape,
    ...RepoConfigSchema.shape,
});

export type GlobalConfig = z.infer<typeof GlobalConfigSchema>;
export type RepoConfig = z.infer<typeof RepoConfigSchema>;
export type MergedConfig = z.infer<typeof MergedConfigSchema>;

import { ANTHROPIC_MODELS, type AnthropicChatModel, anthropicText } from "@tanstack/ai-anthropic";

export { ANTHROPIC_MODELS };

export const PROVIDER_NAMES = ["anthropic"] as const;

export type ProviderName = (typeof PROVIDER_NAMES)[number];

export type ModelName = AnthropicChatModel;

export function createAdapter(provider: ProviderName, model: ModelName) {
    switch (provider) {
        case "anthropic":
            return anthropicText(model);
        default: {
            const _exhaustive: never = provider;
            throw new Error(`Unknown provider: ${_exhaustive}`);
        }
    }
}

