import { parse as parseToml } from "@std/toml";
import {
    GlobalConfigSchema,
    type MergedConfig,
    MergedConfigSchema,
    RepoConfigSchema,
} from "./schema.ts";
import { GLOBAL_CONFIG_PATH, REPO_CONFIG_NAME } from "./paths.ts";

/** Convert snake_case keys to camelCase (single level, no recursion needed for flat config) */
function snakeToCamel(obj: Record<string, unknown>): Record<string, unknown> {
    const result: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(obj)) {
        const camelKey = key.replace(/_([a-z])/g, (_, c) => c.toUpperCase());
        result[camelKey] = value;
    }
    return result;
}

async function readTomlFile(path: string): Promise<Record<string, unknown> | null> {
    try {
        const content = await Deno.readTextFile(path);
        const parsed = parseToml(content);
        return snakeToCamel(parsed as Record<string, unknown>);
    } catch (e) {
        if (e instanceof Deno.errors.NotFound) return null;
        throw e;
    }
}

export async function loadConfig(): Promise<MergedConfig> {
    const globalRaw = await readTomlFile(GLOBAL_CONFIG_PATH);
    const globalConfig = GlobalConfigSchema.parse(globalRaw ?? {});

    const repoRaw = await readTomlFile(REPO_CONFIG_NAME);
    const repoConfig = repoRaw ? RepoConfigSchema.parse(repoRaw) : {};

    return MergedConfigSchema.parse({ ...globalConfig, ...repoConfig });
}

import { Command } from "@cliffy/command";
import * as colors from "@std/fmt/colors";
import { commitCommand } from "./commands/commit.ts";
import { branchCommand } from "./commands/branch.ts";
import { configCommand } from "./commands/config.ts";
import { initCommand } from "./commands/init.ts";

const main = new Command()
    .name("shiplog")
    .version("0.1.0")
    .description("AI-powered git operations")
    .action(function () {
        this.showHelp();
    })
    .command("commit", commitCommand)
    .command("branch", branchCommand)
    .command("config", configCommand)
    .command("init", initCommand);

try {
    await main.parse(Deno.args);
} catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    console.error(colors.red(`Error: ${message}`));
    Deno.exit(1);
}

import { assertEquals, assertThrows } from "jsr:@std/assert";
import { ANTHROPIC_MODELS, createAdapter, PROVIDER_NAMES } from "./adapters.ts";

Deno.test("PROVIDER_NAMES contains anthropic", () => {
    assertEquals(PROVIDER_NAMES, ["anthropic"]);
});

Deno.test("ANTHROPIC_MODELS is a non-empty array of strings", () => {
    assertEquals(Array.isArray(ANTHROPIC_MODELS), true);
    assertEquals(ANTHROPIC_MODELS.length > 0, true);
    for (const model of ANTHROPIC_MODELS) {
        assertEquals(typeof model, "string");
    }
});

Deno.test("createAdapter returns an adapter for valid provider/model", () => {
    const adapter = createAdapter("anthropic", "claude-haiku-4-5");
    assertEquals(typeof adapter, "object");
    assertEquals(adapter !== null, true);
});

Deno.test("createAdapter throws for invalid provider", () => {
    assertThrows(
        // deno-lint-ignore no-explicit-any
        () => createAdapter("openai" as any, "gpt-4" as any),
        Error,
        "Unknown provider",
    );
});

const HOME = Deno.env.get("HOME") ?? "";

export const CONFIG_DIR = `${HOME}/.config/black-atom/shiplog`;
export const GLOBAL_CONFIG_PATH = `${CONFIG_DIR}/config.toml`;
export const REPO_CONFIG_NAME = ".shiplog.toml";
export const REMOTE_SCHEMA_URL =
    "https://raw.githubusercontent.com/black-atom-industries/shiplog/main/schema.json";

import { Command } from "@cliffy/command";
import { stringify as stringifyToml } from "@std/toml";
import * as colors from "@std/fmt/colors";
import { loadConfig } from "../config/loader.ts";
import { CONFIG_DIR, GLOBAL_CONFIG_PATH } from "../config/paths.ts";
import { GlobalConfigSchema } from "../config/schema.ts";

/** Convert camelCase keys to snake_case for TOML output */
function camelToSnake(obj: Record<string, unknown>): Record<string, unknown> {
    const result: Record<string, unknown> = {};
    for (const [key, value] of Object.entries(obj)) {
        const snakeKey = key.replace(/[A-Z]/g, (c) => `_${c.toLowerCase()}`);
        result[snakeKey] = value;
    }
    return result;
}

async function initGlobalConfig(): Promise<void> {
    try {
        await Deno.stat(GLOBAL_CONFIG_PATH);
        console.error(colors.yellow(`Config already exists at ${GLOBAL_CONFIG_PATH}`));
        console.error("Delete it first if you want to regenerate.");
        Deno.exit(1);
    } catch (e) {
        if (!(e instanceof Deno.errors.NotFound)) throw e;
    }

    await Deno.mkdir(CONFIG_DIR, { recursive: true });

    const defaults = GlobalConfigSchema.parse({});
    const tomlContent = stringifyToml(camelToSnake(defaults as Record<string, unknown>));

    await Deno.writeTextFile(GLOBAL_CONFIG_PATH, tomlContent);
    console.log(colors.green(`Config written to ${GLOBAL_CONFIG_PATH}`));
}

async function showConfig(): Promise<void> {
    const config = await loadConfig();
    console.log(stringifyToml(camelToSnake(config as Record<string, unknown>)));
}

export const configCommand = new Command()
    .description("Manage global configuration")
    .option("--init", "Create default global config")
    .option("--show", "Show resolved config")
    .action(async (options) => {
        if (options.init) {
            await initGlobalConfig();
        } else if (options.show) {
            await showConfig();
        } else {
            console.error("Use --init or --show. See --help for details.");
            Deno.exit(1);
        }
    });

import { Command } from "@cliffy/command";
import * as colors from "@std/fmt/colors";
import { REPO_CONFIG_NAME } from "../config/paths.ts";
import { isGitRepo } from "../git/diff.ts";

export const initCommand = new Command()
    .description("Create repo-local .shiplog.toml config")
    .action(async () => {
        if (!await isGitRepo()) {
            console.error(colors.red("Error: Not in a git repository"));
            Deno.exit(1);
        }

        try {
            await Deno.stat(REPO_CONFIG_NAME);
            console.error(colors.yellow(`${REPO_CONFIG_NAME} already exists`));
            console.error("Delete it first if you want to regenerate.");
            Deno.exit(1);
        } catch (e) {
            if (!(e instanceof Deno.errors.NotFound)) throw e;
        }

        const content = [
            `# use_lazygit = true`,
            `# commit_types = ["feat", "fix", "docs", "style", "refactor", "test", "chore", "ci", "perf", "revert"]`,
            `# issue_pattern = "(\\\\w+-\\\\d+)"`,
            `# issue_prefix = ""`,
            "",
        ].join("\n");

        await Deno.writeTextFile(REPO_CONFIG_NAME, content);
        console.log(colors.green(`Created ${REPO_CONFIG_NAME}`));
    });

import { Command } from "@cliffy/command";
import * as colors from "@std/fmt/colors";
import { loadConfig } from "../config/loader.ts";
import type { MergedConfig } from "../config/schema.ts";
import { getCommitHistory, getCurrentBranch, getStagedDiff, isGitRepo } from "../git/diff.ts";
import { commit, forcePush, push } from "../git/operations.ts";
import { generate } from "../ai/client.ts";
import { buildCommitPrompt } from "../ai/commit-prompt.ts";
import { confirmForcePush, editMessage, selectCommitAction, selectModel } from "../ui/prompts.ts";
import { askUserToOpenLazygit } from "../ui/lazygit.ts";
import { runGuidedCommit } from "../ui/commit-builder.ts";

function extractIssueId(branch: string, pattern?: string, prefix?: string): string | undefined {
    if (!pattern) return undefined;
    const match = branch.match(new RegExp(pattern, "i"));
    if (!match) return undefined;

    if (prefix && match[1]) {
        return `${prefix}${match[1]}`;
    }
    return match[0].toUpperCase();
}

async function ensureStagedChanges(useLazygit: boolean): Promise<void> {
    const diff = await getStagedDiff();
    if (diff) return;

    console.error(colors.yellow("No staged changes found."));

    if (useLazygit) {
        const opened = await askUserToOpenLazygit();
        if (opened) {
            const diffAfterStaging = await getStagedDiff();
            if (!diffAfterStaging) {
                console.log("No changes staged. Aborting.");
                Deno.exit(1);
            }
            return;
        }
    }

    console.error("Please stage your changes first.");
    Deno.exit(1);
}

async function generateCommitMessage(
    model: MergedConfig["model"],
    config: MergedConfig,
    quiet = false,
): Promise<string> {
    const [diff, branch, history] = await Promise.all([
        getStagedDiff(),
        getCurrentBranch(),
        getCommitHistory(config.historyCount),
    ]);

    const issueId = extractIssueId(branch, config.issuePattern, config.issuePrefix);

    const prompt = buildCommitPrompt({
        diff,
        commitHistory: history,
        summaryLength: config.summaryLength,
        issueId,
    });

    if (!quiet) {
        console.error(`Generating with ${colors.cyan(model)}...`);
    }
    const message = await generate(prompt, model, config.provider);
    return message.replace(/^["']|["']$/g, "").replace(/\r/g, "");
}

function displayMessage(message: string, model: string): void {
    console.log("");
    console.log(`Generated commit message (${colors.cyan(model)}):`);
    console.log(colors.dim("─".repeat(40)));
    console.log(colors.yellow(message));
    console.log(colors.dim("─".repeat(40)));
    console.log("");
}

async function handlePush(pushFlag: boolean, forceFlag: boolean): Promise<void> {
    if (!pushFlag) return;

    console.log("");
    console.log("Pushing to remote...");

    if (forceFlag) {
        await forcePush();
        console.log(colors.green("\nAll done! Changes committed and force pushed successfully!\n"));
        return;
    }

    const result = await push();
    if (result.success) {
        console.log(colors.green("\nAll done! Changes committed and pushed successfully!\n"));
        return;
    }

    console.log("");
    console.error(colors.red("Push failed:"));
    console.error(result.output);
    console.log("");

    if (await confirmForcePush()) {
        await forcePush();
        console.log(colors.green("\nAll done! Changes committed and force pushed successfully!\n"));
    } else {
        console.log("Push cancelled.");
        Deno.exit(1);
    }
}

export const commitCommand = new Command()
    .description("Commit changes (manual or AI-powered)")
    .option("-s, --smart", "Use AI to generate commit message")
    .option("-y, --yes", "Auto-confirm (with -s only)")
    .option("-r, --raw", "Print raw message to stdout, no commit (requires -sy)")
    .option("-p, --push", "Push after commit")
    .option("-f, --force", "Force push with --force-with-lease")
    .action(async (options) => {
        if (!await isGitRepo()) {
            console.error(colors.red("Error: Not in a git repository"));
            Deno.exit(1);
        }

        const config = await loadConfig();

        if (options.raw) {
            if (!options.smart || !options.yes) {
                console.error(
                    colors.red("Error: --raw must be used with --smart and --yes (-syr)"),
                );
                Deno.exit(1);
            }
            await ensureStagedChanges(config.useLazygit);
            const message = await generateCommitMessage(config.model, config, true);
            console.log(message);
            return;
        }

        if (!options.smart) {
            await ensureStagedChanges(config.useLazygit);
            await runGuidedCommit(config);
            await handlePush(!!options.push, !!options.force);
            return;
        }

        let currentModel = config.model;
        await ensureStagedChanges(config.useLazygit);
        let commitMessage: string;
        try {
            commitMessage = await generateCommitMessage(currentModel, config);
        } catch (error) {
            console.error(colors.red(`Failed to generate commit message: ${error}`));
            Deno.exit(1);
        }
        displayMessage(commitMessage, currentModel);

        if (options.yes) {
            console.log("Auto-committing (--yes flag)...");
            await commit(commitMessage);
            console.log(colors.green("\nChanges committed successfully!"));
            await handlePush(!!options.push, !!options.force);
            return;
        }

        // Interactive loop
        while (true) {
            const action = await selectCommitAction();

            switch (action) {
                case "commit":
                    console.log("\nCommitting changes...");
                    await commit(commitMessage);
                    console.log(colors.green("\nChanges committed successfully!"));
                    await handlePush(!!options.push, !!options.force);
                    return;

                case "edit": {
                    const edited = await editMessage(commitMessage);
                    if (edited) {
                        console.log("\nCommitting with edited message...");
                        await commit(edited);
                        console.log(colors.green("\nChanges committed successfully!"));
                        await handlePush(!!options.push, !!options.force);
                    } else {
                        console.log("Commit cancelled (empty message).");
                        Deno.exit(1);
                    }
                    return;
                }

                case "regenerate": {
                    const selected = await selectModel(config.models);
                    currentModel = selected;
                    try {
                        commitMessage = await generateCommitMessage(currentModel, config);
                        displayMessage(commitMessage, currentModel);
                    } catch (error) {
                        console.error(colors.red(`Failed to regenerate: ${error}`));
                        console.log("Using previous message.");
                    }
                    break;
                }

                case "cancel":
                    console.log("Commit cancelled.");
                    Deno.exit(1);
            }
        }
    });

import { Command } from "@cliffy/command";
import * as colors from "@std/fmt/colors";
import { loadConfig } from "../config/loader.ts";
import type { MergedConfig } from "../config/schema.ts";
import { switchToNewBranch } from "../git/operations.ts";
import { isGitRepo } from "../git/diff.ts";
import { generate } from "../ai/client.ts";
import { buildBranchPrompt } from "../ai/branch-prompt.ts";
import { selectBranchAction, selectModel } from "../ui/prompts.ts";

async function generateBranchName(
    description: string,
    model: MergedConfig["model"],
    config: MergedConfig,
    quiet = false,
): Promise<string> {
    const prompt = buildBranchPrompt({ description });

    if (!quiet) {
        console.error(`Generating with ${colors.cyan(model)}...`);
    }
    const name = await generate(prompt, model, config.provider);
    return name.replace(/^["']|["']$/g, "").replace(/[\n\r]/g, "");
}

function displayBranchName(name: string, model: string): void {
    console.log("");
    console.log(`Generated branch name (${colors.cyan(model)}):`);
    console.log(colors.dim("─".repeat(40)));
    console.log(colors.yellow(name));
    console.log(colors.dim("─".repeat(40)));
    console.log("");
}

export const branchCommand = new Command()
    .description("Create branches (manual or AI-powered)")
    .arguments("[description...:string]")
    .option("-s, --smart", "Use AI to generate branch name")
    .option("-y, --yes", "Auto-create branch (with -s only)")
    .option("-r, --raw", "Print raw name to stdout, no branch creation (requires -sy)")
    .action(async (options, ...descriptionParts) => {
        if (!await isGitRepo()) {
            console.error(colors.red("Error: Not in a git repository"));
            Deno.exit(1);
        }

        const description = descriptionParts.join(" ");

        if (!description) {
            console.error(colors.red("Error: No branch name or description provided"));
            console.error("Use 'shiplog branch --help' for usage information");
            Deno.exit(1);
        }

        if (options.raw) {
            if (!options.smart || !options.yes) {
                console.error(
                    colors.red("Error: --raw must be used with --smart and --yes (-syr)"),
                );
                Deno.exit(1);
            }
            const config = await loadConfig();
            const name = await generateBranchName(description, config.model, config, true);
            console.log(name);
            return;
        }

        if (!options.smart) {
            console.log(`Creating branch: ${colors.cyan(description)}`);
            await switchToNewBranch(description);
            console.log(
                colors.green(`\nBranch '${description}' created and switched successfully!`),
            );
            return;
        }

        const config = await loadConfig();
        let currentModel = config.model;
        let branchName: string;
        try {
            branchName = await generateBranchName(description, currentModel, config);
        } catch (error) {
            console.error(colors.red(`Failed to generate branch name: ${error}`));
            Deno.exit(1);
        }
        displayBranchName(branchName, currentModel);

        if (options.yes) {
            console.log("Auto-creating branch (--yes flag)...");
            await switchToNewBranch(branchName);
            console.log(
                colors.green(`\nBranch '${branchName}' created and switched successfully!`),
            );
            return;
        }

        // Interactive loop
        while (true) {
            const action = await selectBranchAction();

            switch (action) {
                case "create":
                    console.log("\nCreating branch...");
                    await switchToNewBranch(branchName);
                    console.log(
                        colors.green(`\nBranch '${branchName}' created and switched successfully!`),
                    );
                    return;

                case "regenerate": {
                    const selected = await selectModel(config.models);
                    currentModel = selected;
                    try {
                        branchName = await generateBranchName(description, currentModel, config);
                        displayBranchName(branchName, currentModel);
                    } catch (error) {
                        console.error(colors.red(`Failed to regenerate: ${error}`));
                        console.log("Using previous name.");
                    }
                    break;
                }

                case "cancel":
                    console.log("Branch creation cancelled.");
                    Deno.exit(1);
            }
        }
    });

