export { OpenRouterTextAdapter, createOpenRouterText, openRouterText, type OpenRouterConfig, type OpenRouterTextModelOptions, } from './adapters/text.js';
export { OpenRouterSummarizeAdapter, createOpenRouterSummarize, openRouterSummarize, type OpenRouterSummarizeConfig, type OpenRouterSummarizeProviderOptions, } from './adapters/summarize.js';
export { OpenRouterImageAdapter, createOpenRouterImage, openRouterImage, type OpenRouterImageConfig, } from './adapters/image.js';
