    const schema = z.toJSONSchema(MergedConfigSchema);
    const converted = convertKeysToSnakeCase(schema as Record<string, unknown>);

    // Also convert the required array to snake_case to match property names
    if (Array.isArray(converted.required)) {
        converted.required = converted.required.map((key: string) =>
            key.replace(/[A-Z]/g, (c) => `_${c.toLowerCase()}`)
        );
    }

    return JSON.stringify(converted, null, 2);
}

