        assertEquals(config.summaryLength, 72);
        assertEquals(config.historyCount, 10);
        assertEquals(config.issuePattern, undefined);
        assertEquals(config.issuePrefix, undefined);
    } finally {
        Deno.chdir(origCwd);
        await Deno.remove(dir, { recursive: true });
    }
});

